import pandas as pd, ast, numpy as np, math
cf=pd.read_csv('/work/wind_profile_20260613_131627.csv')['value'].map(lambda v: ast.literal_eval(v)['electricity']).to_numpy(float)
load=30; eta=.9; B=30
# max zero run
run=maxrun=0
for x in cf:
    if x==0: run+=1; maxrun=max(maxrun,run)
    else: run=0
print('zeros',np.sum(cf==0),'maxrun',maxrun)
# feasibility helper
def max_circ(d):
    max_end=max_so=0; min_end=min_so=0; total=0
    for x in d:
        total+=x; max_end=max(0,max_end+x); max_so=max(max_so,max_end); min_end=min(0,min_end+x); min_so=min(min_so,min_end)
    return max(max_so,total-min_so,0)
def feasible(W):
    gen=W*cf; surplus=np.maximum(gen-load,0); deficit=np.maximum(load-gen,0)
    if B<deficit.max()-1e-9: return False, math.inf, deficit.max()
    p=eta*np.minimum(surplus,B); q=deficit/eta
    req=max_circ(q-p); return p.sum()>=q.sum() and req<=3.2*B, req, deficit.max()
for W in [221,500,1000,2000,5000,10000]: print(W, feasible(W))

